struct AppliedPromotion: Identifiable, Codable, Equatable {
    let id: UUID
    let code: String
    let discount: Int
    let appliedAt: Date
}

final class PromoStore: ObservableObject {
    static let shared = PromoStore()

    @Published var appliedPromotions: [AppliedPromotion] = []

    private let storageKey = "applied_promotions_v1"

    func reload() {
        appliedPromotions = load()
    }

    func apply(code: String, discount: Int) {
        let promo = AppliedPromotion(id: UUID(), code: code, discount: discount, appliedAt: Date())
        var current = load()
        current.append(promo)
        save(current)
        DispatchQueue.main.async {
            self.appliedPromotions = current
        }
    }

    private func load() -> [AppliedPromotion] {
        guard let data = UserDefaults.standard.data(forKey: storageKey) else { return [] }
        return (try? JSONDecoder().decode([AppliedPromotion].self, from: data)) ?? []
    }

    private func save(_ promotions: [AppliedPromotion]) {
        guard let data = try? JSONEncoder().encode(promotions) else { return }
        UserDefaults.standard.set(data, forKey: storageKey)
    }
}

final class PromoLinkHandler {
    static let shared = PromoLinkHandler()

    var onPromotionApplied: ((AppliedPromotion) -> Void)?

    func handle(url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return }
        guard components.host == "myapp.com" || components.host == "www.myapp.com" else { return }
        guard components.path == "/promo" else { return }

        let queryItems = components.queryItems ?? []
        guard let code = queryItems.first(where: { $0.name.lowercased() == "code" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines),
              !code.isEmpty,
              let discountString = queryItems.first(where: { $0.name.lowercased() == "discount" })?.value,
              let discount = Int(discountString),
              (0...100).contains(discount) else { return }

        applyPromotionToUserAccounts(code: code, discount: discount)
    }

    private func applyPromotionToUserAccounts(code: String, discount: Int) {
        let promo = AppliedPromotion(id: UUID(), code: code, discount: discount, appliedAt: Date())
        PromoStore.shared.apply(code: code, discount: discount)
        DispatchQueue.main.async {
            self.onPromotionApplied?(promo)
        }
    }
}

